prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?task
  ?taskName
  (COUNT(DISTINCT ?startReachable) AS ?incomingFromStartCount)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "0b4394edaa09437d93cc54c78c0180cb" ;
         tai:belongsTo ?org .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  ?choreo tai:belongsTo+ ?model .

  OPTIONAL {
    ?start a bboExt:StartEvent ;
           tai:belongsTo ?choreo2 .
    FILTER(?choreo2 = ?choreo)

    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
    OPTIONAL { ?task bbo:name ?taskName . }
    BIND(?start AS ?startReachable)
  }

  OPTIONAL { ?task bbo:name ?taskName . }
}
GROUP BY ?task ?taskName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?model
  ?modelName
  ?normId
  ?origId
  ?created
  ?org
WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  FILTER(
    STRENDS(STR(?normId), "0b4394edaa09437d93cc54c78c0180cb") ||
    STRENDS(STR(?origId), "0b4394edaa09437d93cc54c78c0180cb")
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?task
  ?taskName
  (COUNT(DISTINCT ?startReachable) AS ?incomingFromStartCount)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "0b4394edaa09437d93cc54c78c0180cb" ;
         tai:belongsTo ?org .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  ?choreo tai:belongsTo+ ?model .

  OPTIONAL {
    ?start a bboExt:StartEvent ;
           tai:belongsTo ?choreo2 .
    FILTER(?choreo2 = ?choreo)

    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
    OPTIONAL { ?task bbo:name ?taskName . }

    BIND(?start AS ?startReachable)
  }

  OPTIONAL { ?task bbo:name ?taskName . }
}
GROUP BY ?task ?taskName
ORDER BY DESC(?incomingFromStartCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?task) AS ?totalTasks)
  (COUNT(DISTINCT ?reachableTask) AS ?reachableTasks)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "0b4394edaa09437d93cc54c78c0180cb" ;
         tai:belongsTo ?org .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  ?choreo tai:belongsTo+ ?model .

  OPTIONAL {
    ?start a bboExt:StartEvent ;
           tai:belongsTo ?choreo2 .
    FILTER(?choreo2 = ?choreo)

    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .

    BIND(?task AS ?reachableTask)
  }
}
GROUP BY ?model
